#include<bits/stdc++.h>
using namespace std;
const int N=500010,M=500010;
int dfn[N],dis[N],low[N],a[N],dfncnt,id[N],sum[N],scccnt;
bool instk[N];
stack<int> s;
bool vis[N];
int cnt,head[N],to[M],val[M],nxt[M];
vector<int> mp[N];
int in[N],dp[N];
void add(int u,int v,int w=1)
{
	to[++cnt]=v;
	val[cnt]=w;
	nxt[cnt]=head[u];
	head[u]=cnt;
}
void tarjan(int x)
{
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    instk[x]=1;
    for(int i=head[x];i;i=nxt[i])
    {
        int v=to[i];
        if(dfn[v]==0)
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(dfn[x]==low[x])
    {
        scccnt++;
        int top;
        do
        {
            top=s.top();
            instk[top]=0;
            sum[scccnt]+=a[top];
            id[top]=scccnt;
            s.pop();
        }while(top!=x);
    }
}
void spfa(int start)
{
	queue<int> q;
	q.push(start);
	dis[start]=sum[start];
	while(!q.empty())
	{
		int t=q.front();
		q.pop();
		vis[t]=0;
		for(int v:mp[t])
		{
			if(dis[v]<dis[t]+sum[v])
			{
				dis[v]=dis[t]+sum[v];
				if(!vis[v])
				{
					vis[v]=1;
					q.push(v);
				}
			}
		}
	}
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        add(u,v);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        if(!dfn[i])
        {
            tarjan(i);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int k=head[i];k;k=nxt[k])
        {
            int j=to[k];
            if(id[i]!=id[j])
            {
                mp[id[i]].push_back(id[j]);
                in[id[j]]++;
            }
        }
    }
    int s,p;
    scanf("%d%d",&s,&p);
    spfa(id[s]);
    int ans=0;
    for(int i=1;i<=p;i++)
    {
        int x;
        scanf("%d",&x);
        ans=max(ans,dis[id[x]]);
    }
    printf("%d",ans);
    return 0;
}
